import{_ as i,c as l,o as t,a1 as a}from"./chunks/framework.DDNAyvCW.js";const p=JSON.parse('{"title":"Skills Troubleshooting & Best Practices","description":"","frontmatter":{},"headers":[],"relativePath":"docs/skills/troubleshooting/index.md","filePath":"docs/skills/troubleshooting/index.md"}'),o={name:"docs/skills/troubleshooting/index.md"};function s(r,e,n,c,d,h){return t(),l("div",null,e[0]||(e[0]=[a('<h1 id="skills-troubleshooting-best-practices" tabindex="-1">Skills Troubleshooting &amp; Best Practices <a class="header-anchor" href="#skills-troubleshooting-best-practices" aria-label="Permalink to &quot;Skills Troubleshooting &amp; Best Practices&quot;">​</a></h1><p>This page covers how to write high-quality Skills, optimize performance, and avoid common pitfalls. For setup instructions, see the <a href="./../usage/">Skills Usage Guide</a>.</p><hr><h2 id="writing-high-quality-skills" tabindex="-1">Writing High-Quality Skills <a class="header-anchor" href="#writing-high-quality-skills" aria-label="Permalink to &quot;Writing High-Quality Skills&quot;">​</a></h2><h3 id="_1-clear-naming-and-descriptions" tabindex="-1">1. Clear naming and descriptions <a class="header-anchor" href="#_1-clear-naming-and-descriptions" aria-label="Permalink to &quot;1. Clear naming and descriptions&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The AI uses the Skill&#39;s description to decide when to apply it. A vague description leads to missed or incorrect matches.</p></div><ul><li><strong>Write specific descriptions</strong>: Clearly explain the purpose and scenarios for the Skill. Include important keywords and state prerequisites and expected outcomes.</li><li><strong>Use consistent naming</strong>: Choose clear, descriptive names. Optionally add category prefixes such as <code>k8s-</code>, <code>docker-</code>, <code>git-</code>. Keep naming conventions consistent across all Skills.</li></ul><h3 id="_2-structured-steps" tabindex="-1">2. Structured steps <a class="header-anchor" href="#_2-structured-steps" aria-label="Permalink to &quot;2. Structured steps&quot;">​</a></h3><ul><li><p><strong>Keep the logic clear</strong></p><ul><li>Order steps by execution sequence.</li><li>Use numbered lists to make order explicit.</li><li>Add necessary decisions and branches where behavior splits.</li></ul></li><li><p><strong>Be detailed and concrete</strong></p><ul><li>Include full commands and parameters.</li><li>Explain the intent of each step.</li><li>Provide examples and expected outputs where helpful.</li></ul></li></ul><h3 id="_3-error-handling-and-rollback" tabindex="-1">3. Error handling and rollback <a class="header-anchor" href="#_3-error-handling-and-rollback" aria-label="Permalink to &quot;3. Error handling and rollback&quot;">​</a></h3><ul><li><p><strong>Handle failure cases</strong></p><ul><li>Identify likely error conditions.</li><li>Include steps for handling each error path.</li><li>Describe how to tell whether an operation succeeded or failed.</li></ul></li><li><p><strong>Define rollback procedures</strong></p><ul><li>For operations that might have impact, provide rollback steps.</li><li>Explain how to restore the system to its previous state.</li></ul></li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Skills that modify infrastructure or data should always include a rollback section. Without one, a failed operation can leave the system in an inconsistent state.</p></div><h3 id="_4-maintainability" tabindex="-1">4. Maintainability <a class="header-anchor" href="#_4-maintainability" aria-label="Permalink to &quot;4. Maintainability&quot;">​</a></h3><ul><li><p><strong>Use variables instead of hard-coding</strong></p><ul><li>Avoid hard-coded values where possible.</li><li>Use placeholders (e.g., <code>&lt;pod-name&gt;</code>, <code>&lt;namespace&gt;</code>) to keep the Skill reusable.</li><li>Document what each variable means and its valid range.</li></ul></li><li><p><strong>Design with modularity</strong></p><ul><li>Break complex workflows into smaller, focused sections.</li><li>Make each step responsible for a single concern.</li><li>Keep Skills easy to test and modify over time.</li></ul></li></ul><hr><h2 id="performance-optimization" tabindex="-1">Performance Optimization <a class="header-anchor" href="#performance-optimization" aria-label="Permalink to &quot;Performance Optimization&quot;">​</a></h2><h3 id="control-the-number-of-enabled-skills" tabindex="-1">Control the number of enabled Skills <a class="header-anchor" href="#control-the-number-of-enabled-skills" aria-label="Permalink to &quot;Control the number of enabled Skills&quot;">​</a></h3><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Every enabled Skill is injected into the AI system prompt. Too many enabled Skills increase token usage and can dilute the AI&#39;s focus.</p></div><ul><li><strong>Enable only what you need</strong>: Turn on only the Skills that are relevant to your current task. Periodically clean up Skills that are no longer used.</li><li><strong>Load by scenario</strong>: Switch different Skill sets based on the current task. Use grouping to manage Skills by scenario and maintain different collections for different workflows.</li></ul><h3 id="optimize-skill-content" tabindex="-1">Optimize Skill content <a class="header-anchor" href="#optimize-skill-content" aria-label="Permalink to &quot;Optimize Skill content&quot;">​</a></h3><ul><li><strong>Streamline steps</strong>: Remove unnecessary steps, combine steps that can safely run in parallel, and optimize command order for faster feedback.</li><li><strong>Reduce complexity</strong>: Avoid overly complex conditional logic inside a single Skill. Split very complex Skills into multiple simpler ones. Store large blocks of content in resource files instead of inline text.</li></ul><hr><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><h3 id="terminal-skills-official-repository" tabindex="-1">Terminal Skills official repository <a class="header-anchor" href="#terminal-skills-official-repository" aria-label="Permalink to &quot;Terminal Skills official repository&quot;">​</a></h3><ul><li><strong>GitHub</strong>: <a href="https://github.com/chaterm/terminal-skills" target="_blank" rel="noreferrer">chaterm/terminal-skills</a></li><li><strong>Description</strong>: A curated collection of terminal-focused Skills covering a variety of operations and development use cases.</li></ul><hr><h2 id="what-to-read-next" tabindex="-1">What to Read Next <a class="header-anchor" href="#what-to-read-next" aria-label="Permalink to &quot;What to Read Next&quot;">​</a></h2><ul><li>For setup and usage instructions, see the <a href="./../usage/">Skills Usage Guide</a>.</li><li>To learn about the settings UI, see <a href="/docs/settings/skills/">Skills Settings</a>.</li></ul>',28)]))}const m=i(o,[["render",s]]);export{p as __pageData,m as default};
